/* ─── Import Error Banner ─── */
.import-error-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  background: rgba\(239, 68, 68, 0.12\);
  border-bottom: 1px solid rgba\(239, 68, 68, 0.3\);
